package com.parkflow.mall.payment.controller;
import com.parkflow.mall.payment.dto.PaymentDtos.*; import com.parkflow.mall.payment.service.PaymentService; import org.springframework.web.bind.annotation.*; import io.jsonwebtoken.*; import io.jsonwebtoken.security.Keys; import java.nio.charset.StandardCharsets;
@RestController @RequestMapping("/api/payments") public class PaymentController { private final PaymentService service; @org.springframework.beans.factory.annotation.Value("${app.jwt-secret:parkflow-local-development-secret-change-me-2026}") String jwtSecret; public PaymentController(PaymentService s){service=s;} @PostMapping("/orders") public OrderResponse create(@RequestBody CreateOrderRequest r,@RequestHeader(value="Idempotency-Key",required=false) String key){return service.create(r,key);}@GetMapping("/orders/{id}") public OrderResponse get(@PathVariable String id){return service.get(id);}@PostMapping("/simulations/success") public SimulationResponse simulate(@RequestBody SimulateRequest r,@RequestHeader(value="Idempotency-Key",required=false) String key){return service.simulate(r,key);}@PostMapping("/reconciliation/run") public java.util.Map<String,Object> reconcile(@RequestHeader(value="Authorization",required=false)String a,@RequestBody(required=false) java.util.Map<String,Object> r){admin(a);return service.reconcile(!Boolean.FALSE.equals(r==null?null:r.get("includeExpiredPending")),!Boolean.FALSE.equals(r==null?null:r.get("retryParkingUpdates")));}@GetMapping("/reconciliation/items") public java.util.List<java.util.Map<String,Object>> items(@RequestHeader(value="Authorization",required=false)String a){admin(a);return service.listItems();}@GetMapping("/reconciliation/items/{id}") public java.util.Map<String,Object> item(@RequestHeader(value="Authorization",required=false)String a,@PathVariable String id){admin(a);return service.item(id);} private void admin(String a){if(a==null||!a.startsWith("Bearer "))throw new org.springframework.web.server.ResponseStatusException(org.springframework.http.HttpStatus.UNAUTHORIZED,"Admin token required");try{Object roles=Jwts.parser().verifyWith(Keys.hmacShaKeyFor(jwtSecret.getBytes(StandardCharsets.UTF_8))).build().parseSignedClaims(a.substring(7)).getPayload().get("roles");if(!(roles instanceof java.util.List<?> l)||l.stream().noneMatch(x->"ADMIN".equals(x.toString())))throw new org.springframework.web.server.ResponseStatusException(org.springframework.http.HttpStatus.FORBIDDEN,"ADMIN role required");}catch(org.springframework.web.server.ResponseStatusException e){throw e;}catch(Exception e){throw new org.springframework.web.server.ResponseStatusException(org.springframework.http.HttpStatus.UNAUTHORIZED,"Invalid admin token");}} }
